 # self.k = Tournament.find\_best\_k()
 self.k = 1
 self.adj\_matrix = self.calculate\_adj\_matrix()
 self.round\_win\_counts = defaultdict(Counter)
 self.round\_winners = defaultdict(list)
 self.previous\_round\_winners = []

 def get\_opponent(self, round\_num, team):
 if round\_num == 0:
 team\_index = self.teams.index(team)
 return self.teams[team\_index + 1 if team\_index % 2 == 0 else team\_index - 1]
 else:
 previous\_round\_winners = self.round\_winners[round\_num - 1]
 team\_index = previous\_round\_winners.index(team)
 return previous\_round\_winners[team\_index + 1 if team\_index % 2 == 0 else team\_index - 1]

 def calculate\_adj\_matrix(self):
