        // iconsInset = (newWidth - iconsSize) - 1
        // This calculation seems to be an attempt to center the icon while accommodating the specific corner placements.
        let iconsInset = (newWidth - iconsSize) - 1 

        // --- Logic based on your requirements ---
        // Array: [A, B, C, ...]
        // Requirement: Only A (layers[0]) and B (layers[1]) are used.
        // Requirement: A should be in the bottom-left corner.
        // Requirement: B should be in the top-right corner, *behind* A.

        guard layers.count >= 2 else {
            // If we don't have at least two images, just draw what we have (or nothing)
            for layer in layers {
                layer.draw(in: rect)
            }
            return
        }

        let imageA = layers[0] // Bottom Left
        let imageB = layers[1] // Top Right (must be drawn first to be in the back)

        // 1. Draw Image B (Top Right) FIRST, so it goes to the background layer.
        // Corresponds to Android index 0 logic (inset on the left, 0 on top/bottom, inset on right)
        // Note: The Android logic was complex, we are mapping the intended visual result:
        // Original Android Index 0: setLayerInset(index, iconsInset, 0, 0, iconsInset) -> Left/Right inset
        let rectB = CGRect(x: iconsInset, y: 0, width: iconsSize, height: iconsSize)
        imageB.draw(in: rectB)

        // 2. Draw Image A (Bottom Left) SECOND, so it goes on top of B.
        // Corresponds to Android index 1 logic (0 on left, inset on top/bottom, 0 on right)
        // Original Android Index 1: setLayerInset(index, 0, iconsInset, iconsInset, 0) -> Top/Bottom inset
        let rectA = CGRect(x: 0, y: iconsInset, width: iconsSize, height: iconsSize)
        imageA.draw(in: rectA)
