package mylog

import (
	"fmt"
	"io"
	"os"
	"sync"
	"time"
)

// =============================================================================
// STEP 1: Define the logging levels
// =============================================================================

// LogLevel defines the severity of a log message.
type LogLevel int

// Define constants for each logging level. iota automatically increments the value.
const (
	LogLevelDebug LogLevel = iota // 0: Detailed information, typically only of interest when diagnosing problems.
	LogLevelInfo                   // 1: Confirmation that things are working as expected.
	LogLevelWarning                // 2: An indication that something unexpected happened, or indicative of some problem in the near future (e.g., 'disk space low'). The software is still working as expected.
	LogLevelError                  // 3: Due to a more serious problem, the software has not been able to perform some function.
	LogLevelFatal                  // 4: A severe error, indicating the application should probably stop.
)

// logLevelNames maps the LogLevel integer back to a readable string for formatting.
var logLevelNames = []string{
	"DEBUG",
	"INFO",
	"WARNING",
	"ERROR",
	"FATAL",
}

// =============================================================================
// STEP 2: Define the logging format
// =============================================================================

// Formatter is a function signature that dictates how a log entry should look.
// It takes the level, the fully formatted message content, and the time it occurred.
type Formatter func(level LogLevel, message string, timestamp time.Time) string

// DefaultFormatter provides a standard, easy-to-read log format.
// Format: [YYYY-MM-DD HH:MM:SS] [LEVEL] Message Content
func DefaultFormatter(level LogLevel, message string, timestamp time.Time) string {
	// Use Go's standard time formatting layout: "2006-01-02 15:04:05"
	return fmt.Sprintf("%s [%s] %s\n", timestamp.Format("2006-01-02 15:04:05"), logLevelNames[level], message)
}

// =============================================================================
// STEP 3 & 4: Implement the logging functionality and Configuration
// =============================================================================

// Logger holds the configuration and state for our logging system.
type Logger struct {
	level     LogLevel    // The minimum level to log (e.g., if set to INFO, DEBUG messages are ignored).
	output    io.Writer   // Where the logs go (e.g., os.Stdout, a file handle).
	formatter Formatter  // The function used to structure the final log string.
	mu        sync.Mutex // A mutex to ensure thread safety when multiple goroutines write logs simultaneously.
}

// NewLogger is the constructor function for our Logger. It handles configuration.
// This satisfies the requirement to provide configuration options.
func NewLogger(level LogLevel, output io.Writer, formatter Formatter) *Logger {
	return &Logger{
		level:     level,
		output:    output,
		formatter: formatter,
	}
}

// log is the internal, core function that handles the actual writing process.
// It checks the level, formats the message, and writes it to the output stream.
func (l *Logger) log(level LogLevel, message string, args ...interface{}) {
	// 1. Level Check (Filtering): If the message level is lower than the configured threshold, skip logging.
	if level < l.level {
		return
	}

	// 2. Concurrency Safety: Lock the mutex before modifying shared resources (like writing to the output stream).
	l.mu.Lock()
	defer l.mu.Unlock() // Ensure the lock is released when the function exits.

	timestamp := time.Now()

	// 3. Message Formatting: Format the user-provided message content (e.g., "User %d logged in", 123)
	// before passing it to the custom Formatter.
	formattedContent := fmt.Sprintf(message, args...)

	// 4. Final Formatting: Use the configured Formatter to build the final log line.
	finalLogLine := l.formatter(level, formattedContent, timestamp)

	// 5. Output Writing: Write the final string to the configured io.Writer.
	_, err := l.output.Write([]byte(finalLogLine))
	if err != nil {
		// Fallback: If we can't write to the primary output, log the error to Stderr so we don't lose visibility.
		fmt.Fprintf(os.Stderr, "CRITICAL LOGGING ERROR: Failed to write log message: %v\n", err)
	}
}

// Public methods corresponding to each LogLevel. These are the functions users call.
func (l *Logger) Debug(message string, args ...interface{}) {
	l.log(LogLevelDebug, message, args...)
}

func (l *Logger) Info(message string, args ...interface{}) {
	l.log(LogLevelInfo, message, args...)
}

func (l *Logger) Warning(message string, args ...interface{}) {
	l.log(LogLevelWarning, message, args...)
}

func (l *Logger) Error(message string, args ...interface{}) {
	l.log(LogLevelError, message, args...)
}

// Fatal logs the message and then immediately terminates the application (exit code 1).
func (l *Logger) Fatal(message string, args ...interface{}) {
	l.log(LogLevelFatal, message, args...)
	os.Exit(1) // Critical: Must exit the process after a fatal error.
}
```

