4.  **Connect Target:** Use `eventRule.addTarget(new targets.LambdaFunction(myLambdaFunction))` to establish the connection.

### 4. Example: A Complete, Runnable Snippet (Conceptual)

This example assumes you have a directory structure where your code lives.

```typescript
import * as cdk from 'aws-cdk-lib';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as path from 'path';

export class EventDrivenStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // 1. Define the Lambda Function (The Processor)
    const eventProcessor = new lambda.Function(this, 'MyEventProcessor', {
        runtime: lambda.Runtime.NODEJS_20,
        handler: 'index.handler',
        // IMPORTANT: This points to the folder containing your 'index.js' file
        code: lambda.Code.fromAsset(path.join(__dirname, 'lambda_code')), 
        memorySize: 128,
        timeout: cdk.Duration.seconds(15),
    });

    // 2. Define the Event Bus (The Router)
    const customBus = new events.EventBus(this, 'MyCustomBus', {
        eventBusName: 'MyRealTimeBus',
    });

    // 3. Define the Rule (The Filter)
    const rule = new events.Rule(this, 'MyProcessingRule', {
        eventBus: customBus,
        // This rule only triggers if the event source is 'api.service'
        eventPattern: {
            source: ['api.service'], 
        },
    });

    // 4. Connect the Target (The Action)
    rule.addTarget(new targets.LambdaFunction(eventProcessor));
  }
}
```

