const { Client, GatewayIntentBits } = require('discord.js');

// 2. Create a new client instance
// We specify the intents the bot needs to listen to events (like messages)
const client = new Client({ 
    intents: [
        GatewayIntentBits.Guilds, // Required to interact with guilds (servers)
        GatewayIntentBits.GuildMessages, // Required to read messages
        GatewayIntentBits.MessageContent, // CRITICAL: Required to read the content of messages (commands)
    ] 
});

