    </div>

    <script>
        // --- Setup and Initialization ---

        var isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

        const paintDiv = document.getElementById('paint');
        const numberDiv = document.getElementById('number');
        const clearButton = document.getElementById('clear');
        const canvas = document.getElementById('myCanvas');
        const context = canvas.getContext('2d');

        // Apply responsive CSS based on device
        if (isMobile) {
            paintDiv.style.width = '60%';
            numberDiv.style.width = '30%';
            numberDiv.style.fontSize = '240px';
            clearButton.style.fontSize = '50px';
        } else {
            paintDiv.style.width = '300px';
            numberDiv.style.width = '150px';
            numberDiv.style.fontSize = '120px';
            clearButton.style.fontSize = '35px';
        }

