            img.onload = function() {
                // Draw the image data onto a temporary area (or just use the data)
                // We draw it here to ensure the context is ready for getImageData
                context.drawImage(img, 0, 0, 28, 28);

                // Get the raw pixel data (R, G, B, A for every pixel)
                data = context.getImageData(0, 0, 28, 28).data;

