        tf.loadLayersModel('model/model.json').then(function(model) {
            window.model = model;
            console.log("Model loaded successfully.");
        }).catch(err => {
            console.error("Error loading the model. Ensure 'model/model.json' exists and is correct.", err);
        });


        // --- Touch Events (Mobile Support) ---

        // Set up touch events for mobile, etc
        canvas.addEventListener('touchstart', function (e) {
            var touch = e.touches[0];
            // Dispatch a synthetic mouse event
            canvas.dispatchEvent(new MouseEvent('mousedown', {
                clientX: touch.clientX,
                clientY: touch.clientY
            }));
        }, false);

        canvas.addEventListener('touchend', function (e) {
            canvas.dispatchEvent(new MouseEvent('mouseup', {}));
        }, false);

        canvas.addEventListener('touchmove', function (e) {
            var touch = e.touches[0];
            canvas.dispatchEvent(new MouseEvent('mousemove', {
                clientX: touch.clientX,
                clientY: touch.clientY
            }));
        }, false);


        // --- Prediction Logic ---

        var predict = function(input) {
            if (window.model) {
                // 1. Create a Tensor from the input array
                // The shape needs to be [batch_size, height, width, channels] -> [1, 28, 28, 1]
                const inputTensor = tf.tensor(input).reshape([1, 28, 28, 1]);

                // 2. Predict
                window.model.predict(inputTensor).then(function(scores) {
                    // 3. Process results
                    scores = scores[0];

                    // Find the index (digit) with the highest score
                    let predicted = scores.indexOf(Math.max(...scores));

                    // Display the result
