This is a significant improvement for usability. To achieve this, we need to:

1.  **Define all necessary flags** for both the local side and the remote peer.
2.  **Construct the Wireguard configuration** for *both* sides (local and remote) so the user can copy the peer's configuration.
3.  **Print the complete configuration** for the peer to the console.
4.  **Generate the local configuration** and use it to start the tunnel.
5.  **Generate the Nginx configuration** (which remains largely the same, but we'll ensure it's robust).

Here is the revised, more comprehensive Go program:

```go
package main

import (
	"flag"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"os/exec"
)

// --- Wireguard Flags ---
var (
	// Local Configuration (This machine)
	wgLocalPrivateKey = flag.String("localPrivateKey", "", "Private key for this local WireGuard interface")
	wgLocalListenPort = flag.String("localListenPort", "51820", "Port this local WireGuard interface listens on")
	wgLocalIP         = flag.String("localIP", "10.0.0.1/24", "Local IP address assigned to this machine in the tunnel")

	// Remote Peer Configuration (The other machine)
	wgPeerPublicKey      = flag.String("peerPublicKey", "", "Public key of the remote peer")
	wgPeerEndpoint       = flag.String("peerEndpoint", "", "Endpoint (IP:Port) of the remote peer (e.g., 203.0.113.5:51820)")
	wgPeerAllowedIPs     = flag.String("peerAllowedIPs", "0.0.0.0/0", "Allowed IPs for the peer (0.0.0.0/0 routes all traffic)")
)

// --- Nginx Flags ---
var (
	nginxListenIP    = flag.String("nginxListenIP", "0.0.0.0", "IP address for the nginx to listen on")
	nginxListenPort  = flag.String("nginxListenPort", "80", "Port for the nginx to listen on")
	nginxServerName  = flag.String("nginxServerName", "localhost", "Server name for the nginx server")
	// The proxy target should be the local WireGuard IP/Port
	nginxProxyTarget = flag.String("nginxProxyTarget", "10.0.0.1:51820", "The internal WireGuard IP and Port to proxy traffic to")
)

const wgConfigFile = "wg0.conf"
const nginxConfigFile = "nginx.conf"

func main() {
	flag.Parse()

	// 1. Validation
	if *wgLocalPrivateKey == "" || *wgPeerPublicKey == "" || *wgPeerEndpoint == "" {
		log.Fatal("Error: Local Private Key, Peer Public Key, and Peer Endpoint are required.")
	}

	// --- 2. Generate and Print Peer Configuration ---
	peerConfig := generatePeerConfig()
	fmt.Println("\n=================================================================")
	fmt.Println("      ✅ PEER CONFIGURATION FOR THE REMOTE MACHINE")
	fmt.Println("=================================================================")
	fmt.Println("Copy the content below and save it as wg0.conf on the remote peer's machine:")
	fmt.Println(peerConfig)
	fmt.Println("=================================================================\n")

	// --- 3. Generate Local Configuration ---
	localConfig := generateLocalConfig()
	err := ioutil.WriteFile(wgConfigFile, []byte(localConfig), 0644)
	if err != nil {
		log.Fatalf("Failed to write local WG config: %v", err)
	}
	fmt.Printf("✅ Local WireGuard config written to: %s\n", wgConfigFile)

	// --- 4. Start Wireguard Tunnel ---
	fmt.Println("\n🚀 Attempting to start WireGuard tunnel...")
	cmdWG := exec.Command("wg-quick", "up", wgConfigFile)
	cmdWG.Stdout = os.Stdout
	cmdWG.Stderr = os.Stderr
	err = cmdWG.Run()
	if err != nil {
		log.Fatalf("❌ Failed to start WireGuard tunnel. Ensure 'wg-quick' is installed and the peer is reachable. Error: %v", err)
	}
	fmt.Println("✅ WireGuard tunnel established successfully.")

	// --- 5. Generate Nginx Configuration ---
	nginxConfig := generateNginxConfig()
	err = ioutil.WriteFile(nginxConfigFile, []byte(nginxConfig), 0644)
	if err != nil {
		log.Fatalf("Failed to write Nginx config: %v", err)
	}
	fmt.Printf("✅ Nginx configuration written to: %s\n", nginxConfigFile)

	// --- 6. Start Nginx Proxy ---
	fmt.Println("\n🚀 Attempting to start Nginx proxy...")
	// We run nginx in the background or in a detached way if this were a service,
	// but for a simple script, we run it in the foreground and wait for it to stop.
	cmdNginx := exec.Command("nginx", "-c", nginxConfigFile)
	cmdNginx.Stdout = os.Stdout
	cmdNginx.Stderr = os.Stderr
	err = cmdNginx.Run()
	if err != nil {
		log.Fatalf("❌ Failed to start Nginx. Error: %v", err)
	}
}

// generatePeerConfig creates the configuration block the remote peer needs.
func generatePeerConfig() string {
	return fmt.Sprintf(`
[Peer]
PublicKey = %s
Endpoint = %s
AllowedIPs = %s
`, *wgLocalPrivateKey, *wgLocalIP, *wgPeerAllowedIPs)
}

// generateLocalConfig creates the configuration for THIS machine to run.
func generateLocalConfig() string {
	return fmt.Sprintf(`
[Interface]
PrivateKey = %s
Address = %s
ListenPort = %s

# [Peer] section is added here to connect to the remote peer
[Peer]
PublicKey = %s
Endpoint = %s
AllowedIPs = %s
`, *wgLocalPrivateKey, *wgLocalIP, *wgLocalListenPort, *wgPeerPublicKey, *wgPeerEndpoint, *wgPeerAllowedIPs)
}

// generateNginxConfig creates the Nginx configuration to proxy traffic through the tunnel.
func generateNginxConfig() string {
	return fmt.Sprintf(`
user  nginx;
worker_processes  auto;

error_log  /var/log/nginx/error.log notice;
pid        /var/run/nginx.pid;

events {
    worker_connections  1024;
}

http {
    include       /etc/nginx/mime.types;
    default_type  application/octet-stream;

    log_format  main  '$remote_addr - $remote_user [$time_local] "$request" '
                      '$status $body_bytes_sent "$http_referer" '
                      '"$http_user_agent" "$http_x_forwarded_for"';

    access_log  /var/log/nginx/access.log  main;

    server {
        listen %s:%s;
        server_name %s;

        location / {
            # Proxy traffic to the IP/Port defined within the WireGuard tunnel interface
            proxy_pass http://%s; 
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;
        }
    }
}
`, *nginxListenPort, *nginxListenIP, *nginxServerName, *nginxProxyTarget)
}
```

### How to Use This Program

1.  **Prerequisites:** You must have `wg-quick` and `nginx` installed on the machine running this Go program.
2.  **Compilation:** Compile the Go code:
    ```bash
    go build tunnel_starter.go
    ```
3.  **Execution (Local Machine):** Run the compiled program, providing all the necessary configuration details:

    *   **`localPrivateKey`**: Your machine's private key.
    *   **`localIP`**: The IP you want this machine to have inside the tunnel (e.g., `10.0.0.1/24`).
    *   **`peerPublicKey`**: The *other* machine's public key.
    *   **`peerEndpoint`**: The public IP and port of the *other* machine (e.g., `198.51.100.10:51820`).
    *   **`peerAllowedIPs`**: What traffic should be routed through the tunnel (use `0.0.0.0/0` to route *all* traffic).
    *   **`nginxListenPort`**: The port Nginx should listen on (e.g., `80`).
    *   **`nginxProxyTarget`**: The IP/Port *inside* the tunnel that Nginx should forward requests to (this is usually your local tunnel IP:Port, like `10.0.0.1:51820`).

    **Example Command:**
    ```bash
    ./tunnel_starter \
        -localPrivateKey "YOUR_LOCAL_PRIVATE_KEY" \
        -localIP "10.0.0.1/24" \
        -peerPublicKey "OTHER_PEER_PUBLIC_KEY" \
        -peerEndpoint "198.51.100.10:51820" \
        -peerAllowedIPs "0.0.0.0/0" \
        -nginxListenPort "80" \
        -nginxProxyTarget "10.0.0.1:51820"
    ```

### What the Output Does

When you run this:

1.  **Prints Peer Config:** It immediately prints a large block of text containing the `[Peer]` section, which you **must copy and paste** onto the remote peer's machine so they can complete their setup.
2.  **Creates Local Config:** It saves your machine's configuration to `wg0.conf`.
3.  **Starts Tunnel:** It runs `wg-quick up wg0.conf`.
4.  **Creates Nginx Config:** It saves the proxy configuration to `nginx.conf`.
5.  **Starts Nginx:** It runs `nginx -c nginx.conf`, which now proxies traffic from its public port (`80`) into the tunnel interface (`10.0.0.1:51820`).

