    public object HorseStarts { get; set; } // Use object or a specific type if known
    public List<object> HaveOverflown { get; set; } // Use object or a specific type if known
}

// --- 2. RaceResult Model ---
public class RaceResult
{
    // Primary Key for the result entry itself
    public int Id { get; set; } 

    // Foreign Key linking to the Race
    public Guid RaceId { get; set; } 
    public Race Race { get; set; } // Navigation Property

    // Properties from the JSON Result object
    public string Placement { get; set; }
    public int StartNumber { get; set; }
    public string HorseName { get; set; }
    public string Distance { get; set; }
    public string TotalTime { get; set; }
    public string KMTime { get; set; }
    public string Prize { get; set; }
    public string Driver { get; set; }
    public string Odds { get; set; }

    // Nested object
    public Horse Horse { get; set; } 
}

// --- 3. Race Model (The main object) ---
public class Race
{
    public Guid Id { get; set; }
    public string RaceCode { get; set; }
    public DateTime StartTime { get; set; }
    public int RaceNumber { get; set; }
    public string RaceName { get; set; }
    public decimal PrizeSum { get; set; } // Assuming PrizeSum should be a decimal/numeric type
    public int Distance { get; set; }
    public string StartMethod { get; set; }
    public string TrackName { get; set; }
    public object OverflyddMap { get; set; } // Use object if null or complex
    public string Result { get; set; } // This seems redundant if we store results separately

    // One-to-Many Relationship: A Race has many Results
    public ICollection<RaceResult> Results { get; set; } = new List<RaceResult>();
}
```

### 2. Set up the DbContext

You need a `DbContext` to interact with Entity Framework Core.

```csharp
using Microsoft.EntityFrameworkCore;

public class RacingDbContext : DbContext
{
    public DbSet<Race> Races { get; set; }
    public DbSet<RaceResult> RaceResults { get; set; }

    public RacingDbContext(DbContextOptions<RacingDbContext> options) : base(options) { }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Configure the relationship: One Race has many RaceResults
        modelBuilder.Entity<Race>()
            .HasMany(r => r.Results)
            .WithOne(rr => rr.Race)
            .HasForeignKey(rr => rr.RaceId)
            .OnDelete(DeleteBehavior.Cascade); // If a Race is deleted, its results are deleted

        // Optionally configure keys if needed, though EF Core usually handles this well
        modelBuilder.Entity<Race>()
            .HasKey(r => r.Id);

        modelBuilder.Entity<RaceResult>()
            .HasKey(rr => rr.Id);
    }
}
```

### 3. The Insertion Logic (The Service/Repository)

This code handles deserializing the JSON and saving the entire object graph to the database in one transaction.

```csharp
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class DataService
{
    private readonly RacingDbContext _context;

    public DataService(RacingDbContext context)
    {
        _context = context;
    }

    public async Task<bool> InsertRaceDataAsync(string jsonPayload)
    {
        try
        {
            // 1. Deserialize the JSON string into the main Race object
            var race = JsonSerializer.Deserialize<Race>(jsonPayload);

            if (race == null)
            {
                Console.WriteLine("Error: Deserialization resulted in a null object.");
                return false;
            }

            // 2. Attach and add the Race object. 
            // EF Core will track the Race and all its related Results.
            _context.Races.Add(race);

            // 3. Save all changes (Race and all associated Results) to the database in one transaction
            int savedCount = await _context.SaveChangesAsync();

            Console.WriteLine($"Successfully saved {savedCount} records (1 Race + {race.Results.Count} Results).");
            return true;
        }
        catch (DbUpdateException dbEx)
        {
            Console.WriteLine($"Database Error during save: {dbEx.Message}");
            return false;
        }
        catch (JsonException jsonEx)
        {
            Console.WriteLine($"JSON Parsing Error: {jsonEx.Message}");
            return false;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An unexpected error occurred: {ex.Message}");
            return false;
        }
    }
}
```

### How to Use It (Example Setup)

You would typically set up Dependency Injection (DI) in your `Program.cs` or `Startup.cs` to manage the `DbContext`.

**Example Usage Flow:**

1. **Setup:** Configure your connection string and register `RacingDbContext` with your service provider.
2. **Execution:** Inject `DataService` into your controller or business logic.
3. **Call:** Pass your JSON string to the `InsertRaceDataAsync` method.

**Important Considerations:**

1. **Data Types:** I made assumptions about data types (e.g., `PrizeSum` is `decimal`, `StartTime` is `DateTime`). You must ensure the C# types match the expected column types in your SQL database.
2. **UUIDs:** The JSON uses GUIDs for `Id`. Ensure your database columns for these IDs are of type `UNIQUEIDENTIFIER` (SQL Server) or equivalent.
3. **Nullables:** I used `object` for fields like `Type`, `HorseStarts`, and `OverflyddMap` where the JSON showed `null` or complex structures without clear definitions. If you know the exact structure of these fields, define concrete classes instead of using `object` for better type safety.
4. **Database Schema:** This code assumes you have already created the necessary database schema (tables for `Race` and `RaceResult`) using EF Core Migrations based on the models provided.

